DROP TABLE IF EXISTS `accounts`

CREATE TABLE `accounts` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `code` varchar(50) NOT NULL,
  `name` varchar(255) NOT NULL,
  `type` enum('asset','liability','equity','revenue','expense') NOT NULL,
  `parent_id` int(11) DEFAULT NULL,
  `is_active` tinyint(1) NOT NULL DEFAULT 1,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `code` (`code`),
  KEY `idx_type` (`type`),
  KEY `idx_parent` (`parent_id`)
) ENGINE=InnoDB AUTO_INCREMENT=9 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;



DROP TABLE IF EXISTS `activity_logs`

CREATE TABLE `activity_logs` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) DEFAULT NULL,
  `role` varchar(50) DEFAULT NULL,
  `action` varchar(150) NOT NULL,
  `entity_type` varchar(100) DEFAULT NULL,
  `entity_id` int(11) DEFAULT NULL,
  `property_id` int(11) DEFAULT NULL,
  `details` text DEFAULT NULL,
  `ip_address` varchar(64) DEFAULT NULL,
  `user_agent` varchar(255) DEFAULT NULL,
  `created_at` datetime NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_property_id` (`property_id`),
  KEY `idx_entity` (`entity_type`,`entity_id`),
  KEY `idx_action` (`action`),
  KEY `idx_created_at` (`created_at`)
) ENGINE=InnoDB AUTO_INCREMENT=28863 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;



DROP TABLE IF EXISTS `agent_client_properties`

CREATE TABLE `agent_client_properties` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `agent_client_id` int(11) NOT NULL,
  `property_id` int(11) NOT NULL,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `uniq_client_property` (`agent_client_id`,`property_id`),
  UNIQUE KEY `uniq_property` (`property_id`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_client` (`agent_client_id`)
) ENGINE=InnoDB AUTO_INCREMENT=42 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;



DROP TABLE IF EXISTS `agent_clients`

CREATE TABLE `agent_clients` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `property_id` int(11) DEFAULT NULL,
  `name` varchar(255) NOT NULL,
  `phone` varchar(50) NOT NULL,
  `email` varchar(150) DEFAULT NULL,
  `notes` text DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_property_id` (`property_id`)
) ENGINE=InnoDB AUTO_INCREMENT=25 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;



DROP TABLE IF EXISTS `agent_contract_units`

CREATE TABLE `agent_contract_units` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `agent_contract_id` int(11) NOT NULL,
  `unit_id` int(11) NOT NULL,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `uniq_contract_unit` (`agent_contract_id`,`unit_id`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_contract` (`agent_contract_id`),
  KEY `idx_unit` (`unit_id`)
) ENGINE=InnoDB AUTO_INCREMENT=4 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;



DROP TABLE IF EXISTS `agent_contracts`

CREATE TABLE `agent_contracts` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `property_id` int(11) DEFAULT NULL,
  `agent_client_id` int(11) NOT NULL,
  `terms_type` enum('one_time','monthly') NOT NULL DEFAULT 'one_time',
  `total_amount` decimal(12,2) NOT NULL DEFAULT 0.00,
  `monthly_amount` decimal(12,2) DEFAULT NULL,
  `duration_months` int(11) DEFAULT NULL,
  `start_month` date DEFAULT NULL,
  `instructions` text DEFAULT NULL,
  `commission_percent` decimal(5,2) DEFAULT NULL,
  `rent_total` decimal(12,2) DEFAULT NULL,
  `status` enum('active','completed','cancelled') NOT NULL DEFAULT 'active',
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_user_id` (`user_id`),
  KEY `idx_property_id` (`property_id`),
  KEY `idx_client_property` (`agent_client_id`,`property_id`)
) ENGINE=InnoDB AUTO_INCREMENT=26 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;



DROP TABLE IF EXISTS `agent_lead_stages`

CREATE TABLE `agent_lead_stages` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `stage_key` varchar(50) NOT NULL,
  `label` varchar(100) NOT NULL,
  `color_class` varchar(20) NOT NULL DEFAULT 'secondary',
  `sort_order` int(11) NOT NULL DEFAULT 0,
  `is_won` tinyint(1) NOT NULL DEFAULT 0,
  `is_lost` tinyint(1) NOT NULL DEFAULT 0,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `uniq_user_stage` (`user_id`,`stage_key`),
  KEY `idx_user` (`user_id`),
  KEY `idx_sort` (`user_id`,`sort_order`)
) ENGINE=InnoDB AUTO_INCREMENT=31 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;



DROP TABLE IF EXISTS `campaign_attachments`

CREATE TABLE `campaign_attachments` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `campaign_id` int(11) NOT NULL,
  `filename` varchar(255) NOT NULL,
  `original_name` varchar(255) NOT NULL,
  `file_path` varchar(500) NOT NULL,
  `file_size` int(11) NOT NULL,
  `mime_type` varchar(100) NOT NULL,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_campaign_id` (`campaign_id`),
  CONSTRAINT `campaign_attachments_ibfk_1` FOREIGN KEY (`campaign_id`) REFERENCES `email_campaigns` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;



DROP TABLE IF EXISTS `contact_message_replies`

CREATE TABLE `contact_message_replies` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `contact_message_id` int(11) NOT NULL,
  `user_id` int(11) DEFAULT NULL,
  `reply_message` text NOT NULL,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_message` (`contact_message_id`),
  KEY `idx_created` (`created_at`)
) ENGINE=InnoDB AUTO_INCREMENT=3 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;



DROP TABLE IF EXISTS `contact_messages`

CREATE TABLE `contact_messages` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(150) NOT NULL,
  `email` varchar(150) DEFAULT NULL,
  `phone` varchar(50) DEFAULT NULL,
  `subject` varchar(255) NOT NULL,
  `message` text NOT NULL,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_created` (`created_at`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;



DROP TABLE IF EXISTS `email_campaigns`

CREATE TABLE `email_campaigns` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `title` varchar(200) NOT NULL,
  `subject` varchar(200) NOT NULL,
  `content` longtext NOT NULL,
  `type` enum('newsletter','follow_up','custom') NOT NULL DEFAULT 'newsletter',
  `status` enum('draft','scheduled','sent','paused') NOT NULL DEFAULT 'draft',
  `scheduled_at` datetime DEFAULT NULL,
  `sent_at` datetime DEFAULT NULL,
  `total_recipients` int(11) DEFAULT 0,
  `sent_count` int(11) DEFAULT 0,
  `opened_count` int(11) DEFAULT 0,
  `clicked_count` int(11) DEFAULT 0,
  `created_by` int(11) NOT NULL,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_created_by` (`created_by`),
  KEY `idx_status` (`status`),
  KEY `idx_scheduled_at` (`scheduled_at`)
) ENGINE=InnoDB AUTO_INCREMENT=2 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

\n\nIf you own or manage rental property in Kenya, you already know the headaches: late rent payments, tenant disputes, lost records, and the endless back-and-forth between landlords, agents, and property managers.\n\nThat\'s exactly why we built RentSmart.\n🏢 WHAT IS RENTSMART?\nRentSmart is a modern property management platform built specifically for the Kenyan real estate market. Whether you\'re a landlord with a single block of flats or a property manager handling a portfolio of properties, RentSmart puts everything in one place.\n\n✅ WHAT RENTSMART DOES FOR YOU\n\n📋 Tenant Management\nOnboard tenants digitally, store lease agreements, and track occupancy — all from your phone or computer.\n\n💳 Rent Collection & Tracking\nSend automated rent reminders and track payments in real time. No more chasing tenants manually.\n\n🧾 Financial Reports\nGenerate income statements, payment histories, and arrears reports instantly — perfect for landlords who want full financial visibility.\n\n🔑 Multi-Role Access\nRentSmart supports four user roles — Landlord, Property Manager, Agent, and Realtor — each with their own dashboard and permissions tailored to their work.\n\n📱 Mobile-Friendly\nAccess your property data anytime, anywhere, straight from your smartphone.\n\n💡 WHY PROPERTY PROFESSIONALS LOVE IT\n\n\"I used to spend hours every month chasing rent and updating spreadsheets. RentSmart handles it all — I just log in and everything is there.\"\n— Property Manager, Nairobi\n\n🚀 GET STARTED TODAY\n\nWe\'re currently onboarding new property managers and landlords across Kenya. Whether you manage 5 units or 500, RentSmart scales with you.\n\nBook a Free Demo\n👉 Visit Our Website: https://rentsmart.timestentechnologies.co.ke/\n👉 Call / WhatsApp: +254795155230\n\nWe\'d love to show you how RentSmart can save you time, reduce losses, and bring order to your property management.\n\nWarm regards,\nRentSmart\n<div style=\"text-align:center;margin-bottom:30px;\"><img src=\"https://rentsmart.timestentechnologies.co.ke/public/assets/images/site_logo_1751627446.png\" alt=\"Rent Smart Kenya Logo\" style=\"max-width:200px;max-height:80px;\"></div>\n\nYou\'re receiving this because you\'re a property professional in Kenya. To unsubscribe, reply with \"STOP\".','newsletter','draft','','2026-03-17 20:47:04','9','9','0','0','1','2026-03-17 09:13:41','2026-03-17 23:33:31');


DROP TABLE IF EXISTS `email_tracking`

CREATE TABLE `email_tracking` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `campaign_id` int(11) NOT NULL,
  `user_id` int(11) NOT NULL,
  `email` varchar(100) NOT NULL,
  `sent_at` datetime DEFAULT NULL,
  `opened_at` datetime DEFAULT NULL,
  `clicked_at` datetime DEFAULT NULL,
  `unsubscribed_at` datetime DEFAULT NULL,
  `bounce_reason` varchar(255) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `unique_campaign_user` (`campaign_id`,`user_id`),
  KEY `idx_campaign_id` (`campaign_id`),
  KEY `idx_user_id` (`user_id`),
  CONSTRAINT `email_tracking_ibfk_1` FOREIGN KEY (`campaign_id`) REFERENCES `email_campaigns` (`id`) ON DELETE CASCADE,
  CONSTRAINT `email_tracking_ibfk_2` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;



DROP TABLE IF EXISTS `employee_payments`

CREATE TABLE `employee_payments` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `employee_id` int(11) NOT NULL,
  `amount` decimal(10,2) NOT NULL,
  `pay_date` date NOT NULL,
  `payment_method` enum('cash','check','bank_transfer','card','mpesa','other') NOT NULL DEFAULT 'cash',
  `source_of_funds` enum('rent_balance','cash','bank','mpesa','owner_funds','other') NOT NULL DEFAULT 'cash',
  `notes` text DEFAULT NULL,
  `expense_id` int(11) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;



DROP TABLE IF EXISTS `employees`

CREATE TABLE `employees` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `name` varchar(150) NOT NULL,
  `email` varchar(150) DEFAULT NULL,
  `phone` varchar(50) DEFAULT NULL,
  `salary` decimal(10,2) DEFAULT 0.00,
  `property_id` int(11) DEFAULT NULL,
  `realtor_listing_id` int(11) DEFAULT NULL,
  `role` varchar(50) NOT NULL DEFAULT 'general',
  `status` enum('active','inactive') NOT NULL DEFAULT 'active',
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=16 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;



DROP TABLE IF EXISTS `esign_requests`

CREATE TABLE `esign_requests` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `title` varchar(255) NOT NULL,
  `message` text DEFAULT NULL,
  `requester_user_id` int(11) NOT NULL,
  `recipient_type` enum('user','tenant','realtor_client') NOT NULL,
  `recipient_id` int(11) NOT NULL,
  `entity_type` varchar(50) DEFAULT NULL,
  `entity_id` int(11) DEFAULT NULL,
  `token` varchar(64) NOT NULL,
  `status` enum('pending','signed','declined','expired') NOT NULL DEFAULT 'pending',
  `expires_at` datetime DEFAULT NULL,
  `signed_at` datetime DEFAULT NULL,
  `declined_at` datetime DEFAULT NULL,
  `signer_name` varchar(150) DEFAULT NULL,
  `signature_image` longtext DEFAULT NULL,
  `signature_ip` varchar(64) DEFAULT NULL,
  `signature_user_agent` varchar(255) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `signature_type` enum('draw','upload','initials') DEFAULT NULL,
  `initials` varchar(50) DEFAULT NULL,
  `document_path` varchar(255) DEFAULT NULL,
  `signed_document_path` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `token` (`token`),
  KEY `idx_requester` (`requester_user_id`),
  KEY `idx_recipient` (`recipient_type`,`recipient_id`),
  KEY `idx_entity` (`entity_type`,`entity_id`),
  KEY `idx_status` (`status`)
) ENGINE=InnoDB AUTO_INCREMENT=19 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;



DROP TABLE IF EXISTS `expenses`

CREATE TABLE `expenses` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `property_id` int(11) DEFAULT NULL,
  `unit_id` int(11) DEFAULT NULL,
  `category` varchar(100) NOT NULL,
  `amount` decimal(10,2) NOT NULL,
  `expense_date` date NOT NULL,
  `payment_method` enum('cash','check','bank_transfer','card','mpesa','other') NOT NULL DEFAULT 'cash',
  `source_of_funds` enum('rent_balance','cash','bank','mpesa','owner_funds','other') NOT NULL DEFAULT 'cash',
  `notes` text DEFAULT NULL,
  `attachments` longtext DEFAULT NULL,
  `reference_type` varchar(50) DEFAULT NULL,
  `reference_id` int(11) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=22 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;



DROP TABLE IF EXISTS `facebook_listings`

CREATE TABLE `facebook_listings` (
  `id` int(10) unsigned NOT NULL AUTO_INCREMENT,
  `unit_id` int(11) NOT NULL,
  `facebook_listing_id` varchar(255) NOT NULL,
  `status` enum('active','deleted','expired') DEFAULT 'active',
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT NULL ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `unit_facebook` (`unit_id`,`facebook_listing_id`),
  KEY `unit_id` (`unit_id`),
  KEY `status` (`status`),
  CONSTRAINT `fk_facebook_unit` FOREIGN KEY (`unit_id`) REFERENCES `units` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;



DROP TABLE IF EXISTS `file_shares`

CREATE TABLE `file_shares` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `file_id` int(11) NOT NULL,
  `recipient_type` enum('user','tenant') NOT NULL,
  `recipient_id` int(11) NOT NULL,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `uniq_share` (`file_id`,`recipient_type`,`recipient_id`),
  KEY `idx_file` (`file_id`),
  KEY `idx_recipient` (`recipient_type`,`recipient_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;



DROP TABLE IF EXISTS `file_uploads`

CREATE TABLE `file_uploads` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `filename` varchar(255) NOT NULL,
  `original_name` varchar(255) NOT NULL,
  `file_type` enum('image','document','attachment') NOT NULL,
  `mime_type` varchar(100) NOT NULL,
  `file_size` int(11) NOT NULL,
  `entity_type` enum('property','unit','payment') NOT NULL,
  `entity_id` int(11) NOT NULL,
  `uploaded_by` int(11) NOT NULL,
  `upload_path` varchar(500) NOT NULL,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `idx_entity` (`entity_type`,`entity_id`),
  KEY `idx_uploaded_by` (`uploaded_by`),
  KEY `idx_filename` (`filename`),
  CONSTRAINT `fk_file_uploads_user` FOREIGN KEY (`uploaded_by`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=108 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;



DROP TABLE IF EXISTS `follow_up_schedules`

CREATE TABLE `follow_up_schedules` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
