DROP TABLE IF EXISTS `follow_up_sent_log`

CREATE TABLE `follow_up_sent_log` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `schedule_id` int(11) NOT NULL,
  `user_id` int(11) NOT NULL,
  `sent_at` datetime DEFAULT NULL,
  `opened_at` datetime DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  UNIQUE KEY `unique_schedule_user` (`schedule_id`,`user_id`),
  KEY `idx_schedule_id` (`schedule_id`),
  KEY `idx_user_id` (`user_id`),
  CONSTRAINT `follow_up_sent_log_ibfk_1` FOREIGN KEY (`schedule_id`) REFERENCES `follow_up_schedules` (`id`) ON DELETE CASCADE,
  CONSTRAINT `follow_up_sent_log_ibfk_2` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;



DROP TABLE IF EXISTS `inquiries`

CREATE TABLE `inquiries` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
