\n    {\n        \"title\": \"M-PESA ready\",\n        \"text\": \"Accept payments and keep references organized for quick verification and reporting.\"\n    },\n    {\n        \"title\": \"Secure & reliable\",\n        \"text\": \"Keep your tenant and payment records safe with a cloud-ready setup and clear audit trails.\"\n    },\n    {\n        \"title\": \"Clear dashboards\",\n        \"text\": \"See what is due, what was paid, and what needs action—without digging through spreadsheets.\"\n    },\n    {\n        \"title\": \"Accurate invoicing\",\n        \"text\": \"Rent, utilities, and maintenance are tracked separately so invoices and balances remain correct.\"\n    }\n]','2026-02-11 10:35:22','2026-02-11 10:57:07');
\n    {\n        \"icon\": \"bi bi-house-door\",\n        \"title\": \"Property Management\",\n        \"text\": \"Manage unlimited properties, units, and tenants from one centralized dashboard. Track occupancy rates, rental income, and property performance in real-time.\"\n    },\n    {\n        \"icon\": \"bi bi-cash-coin\",\n        \"title\": \"Rent Collection & Tenant Portal\",\n        \"text\": \"Collect rent via M-PESA and give tenants self-service access to pay, view balances, and track payment history—anytime, anywhere.\"\n    },\n    {\n        \"icon\": \"bi bi-file-earmark-text\",\n        \"title\": \"Lease Management System\",\n        \"text\": \"Create digital lease agreements, track lease terms, and receive automated renewal reminders. Simplify tenant onboarding and documentation.\"\n    },\n    {\n        \"icon\": \"bi bi-graph-up\",\n        \"title\": \"Invoices & Financial Reports\",\n        \"text\": \"Generate invoices and receipts, and access clear reporting on income, expenses, and performance for confident decision-making.\"\n    },\n    {\n        \"icon\": \"bi bi-bell\",\n        \"title\": \"Automated Notifications\",\n        \"text\": \"Stay informed with automated SMS and email notifications for rent due dates, maintenance updates, lease renewals, and payment confirmations.\"\n    },\n    {\n        \"icon\": \"bi bi-lightning-charge\",\n        \"title\": \"Utilities Management\",\n        \"text\": \"Track metered and flat-rate utilities, readings, charges, and payments—so utilities are always clearly separated from rent.\"\n    },\n    {\n        \"icon\": \"bi bi-tools\",\n        \"title\": \"Maintenance Management\",\n        \"text\": \"Log requests, assign work, track progress, and record maintenance costs with clear references for invoices and statements.\"\n    },\n    {\n        \"icon\": \"bi bi-cash-stack\",\n        \"title\": \"Expense Tracking\",\n        \"text\": \"Record property expenses and keep a clear view of profitability with statements and reports by property and time period.\"\n    }\n]','2026-02-11 10:35:22','2026-02-11 10:57:07');
\n    {\n        \"name\": \"Nancy Wanjiru\",\n        \"role\": \"Property Manager\",\n        \"text\": \"\\\"RentSmart has completely transformed how we manage our properties. The automated rent collection and reporting features save us hours every week.\\\"\"\n    },\n    {\n        \"name\": \"James Kamau\",\n        \"role\": \"Landlord\",\n        \"text\": \"\\\"The tenant portal has made communication so much easier. My tenants love being able to pay rent and submit maintenance requests online.\\\"\"\n    },\n    {\n        \"name\": \"David Kibara\",\n        \"role\": \"Real Estate Agent\",\n        \"text\": \"\\\"The financial reports and analytics help me make data-driven decisions. RentSmart has helped us increase our property portfolio\'s performance.\\\"\"\n    }\n]','2026-02-11 10:35:22','2026-02-12 11:17:43');
\n    {\n        \"q\": \"What is RentSmart property management software?\",\n        \"a\": \"RentSmart is a comprehensive cloud-based property management system designed for landlords, property managers, and real estate agents in Kenya. It helps you manage properties, tenants, rent collection, maintenance, utilities, and financial reporting all in one platform. With M-PESA integration and automated features, RentSmart simplifies rental property management.\"\n    },\n    {\n        \"q\": \"How long is the free trial period?\",\n        \"a\": \"RentSmart offers a generous 7-day free trial with full access to all features. No credit card required to start. You can explore all property management features, add properties and tenants, collect rent, and generate reports during the trial period. After 7-day, you can choose a plan that fits your needs.\"\n    },\n    {\n        \"q\": \"Does RentSmart integrate with M-PESA?\",\n        \"a\": \"Yes! RentSmart has full M-PESA integration for seamless rent collection. Tenants can pay rent directly through M-PESA, and payments are automatically recorded in the system. You\'ll receive instant notifications when payments are made, and the system automatically reconciles payments with tenant accounts.\"\n    },\n    {\n        \"q\": \"How many properties can I manage with RentSmart?\",\n        \"a\": \"The number of properties you can manage depends on your subscription plan. Our Basic plan supports up to 10 properties, Professional plan up to 50 properties, and Enterprise plan offers unlimited properties. Each property can have multiple units, and you can manage all of them from a single dashboard.\"\n    },\n    {\n        \"q\": \"Can tenants access the system?\",\n        \"a\": \"Yes! RentSmart includes a dedicated tenant portal where tenants can log in to view their lease details, make rent payments, submit maintenance requests, and access important documents. This self-service portal reduces your workload and improves tenant satisfaction.\"\n    }\n]','2026-02-11 10:35:22','2026-02-11 11:05:25');


DROP TABLE IF EXISTS `subscription_payment_logs`

CREATE TABLE `subscription_payment_logs` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `payment_id` int(11) DEFAULT NULL,
  `log_type` enum('request','response','callback','error') NOT NULL,
  `log_data` text DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `payment_id` (`payment_id`),
  CONSTRAINT `subscription_payment_logs_ibfk_1` FOREIGN KEY (`payment_id`) REFERENCES `subscription_payments` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=36 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;



DROP TABLE IF EXISTS `subscription_payments`

CREATE TABLE `subscription_payments` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `user_id` int(11) NOT NULL,
  `subscription_id` int(11) NOT NULL,
  `amount` decimal(10,2) NOT NULL,
  `payment_method` enum('mpesa','card') NOT NULL,
  `status` enum('pending','completed','failed') NOT NULL DEFAULT 'pending',
  `transaction_reference` varchar(100) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `subscription_payments_user_id_fk` (`user_id`),
  KEY `subscription_payments_subscription_id_fk` (`subscription_id`),
  CONSTRAINT `subscription_payments_subscription_id_fk` FOREIGN KEY (`subscription_id`) REFERENCES `subscriptions` (`id`),
  CONSTRAINT `subscription_payments_user_id_fk` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=64 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;



DROP TABLE IF EXISTS `subscription_plans`

CREATE TABLE `subscription_plans` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(100) NOT NULL,
  `price` decimal(10,2) NOT NULL,
  `description` text DEFAULT NULL,
  `features` text DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `property_limit` int(11) DEFAULT NULL,
  `unit_limit` int(11) DEFAULT NULL,
  `listing_limit` int(11) DEFAULT NULL,
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=5 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

